var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"골목에서도 쏟아져 나온다! 사격 개시!","JPN":"路地の方からもくるぞ！　射撃開始！","ENG":"They're pouring out from the alleys, too! Fire!","TWN":"巷子裡也有侵蝕體！開始射擊！"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"빌어먹을! 또 총알이 걸렸어!","JPN":"くそっ！　弾切れだ！","ENG":"Darn it! My gun's jammed again!","TWN":"該死！卡彈了！"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"여기도 한 명 당했다! 붕대 가져 와!","JPN":"こちら、一人負傷！　止血処置を！","ENG":"Man down! Medic!","TWN":"這裡有人受傷了！快拿紗布過來！"},"stage":{"bg":"PROLOGUE_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"후우...... 도시 한복판에서 전쟁을 치르는군.","JPN":"ふう……都市のど真ん中で戦闘とは。","ENG":"Phew... They've turned downtown into a war zone.","TWN":"呼……沒想到會在市中心開戰。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"늘 있는 정화 작전이라더니, 하여튼 윗대가리 놈들.","JPN":"いつもの浄化作戦とか言いやがって、上のクソどもは。","ENG":"This was supposed to be a routine purification... I knew those top brass fools were up to no good.","TWN":"不是說就是個淨化作戰嗎？上頭這些人真是該死。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"강산아, 부상자들은?","JPN":"ヤマムラ君、負傷者は？","ENG":"Gangsan, what's the latest on casualties?","TWN":"江山，傷患呢？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"네, 팀장님! 지금 인근 구조대에 연락해서 병원으로 이송 중입니다!","JPN":"はい、班長！　今近くの救助隊に連絡して病院に移送中です！","ENG":"Sir! We managed to contact a nearby rescue squad to medevac the wounded!","TWN":"隊長！已經聯繫了附近的救助隊，正在送往醫院。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그래. 현장 잘 통제하고 민간인 절대 못 들어오게 잘 막아라.","JPN":"了解。民間人が絶対に立ち入らないように、現場の通行止めを頼むぞ。","ENG":"Good. Keep the site secure and don't let any civilians through.","TWN":"好，控制好現場，絕對不能讓老百姓進來。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"죄송합니다. 제가 조금만 더 잘 지켰더라도 부상자는 훨씬 적었을 텐데......","JPN":"申し訳ございません。僕がもう少しちゃんと対処していれば負傷者も少なかったはずなのに……","ENG":"I'm sorry, sir. If I did a better job of protecting them, we wouldn't have so many casualties...","TWN":"對不起，都是我的錯，否則也不會有這麼多人受傷……"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"그 사람들도 다 돈 받고 고용된 용병들이야. 자기가 다칠 줄 모르고 왔겠냐.","JPN":"そいつらは金で雇われた傭兵だ。怪我のリスクくらい、事前に承知しているだろ。","ENG":"Those mercs are all getting paid to do this. They knew what they were getting themselves into.","TWN":"那些人都是收錢做事的傭兵，他們應該都有了心理準備。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"아무도 너더러 책임지라고 한 적 없어. 지금 맡은 일에나 신경 써.","JPN":"誰も君に責任を負えなんて言わないから、今の仕事に集中しろ。","ENG":"Nobody expects you to take responsibility for them. Just focus on the task at hand.","TWN":"沒人讓你負責，你只要做好你自己的事就行了。"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L22_1","type":"dialog","speaker":"GANGSAN_DAYMINE_NULL_NULL","text":{"KOREA":"네! 시정하겠습니다!","JPN":"はい、是正します！","ENG":"Understood, sir!","TWN":"是！遵命！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GANGSAN_DAYMINE_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"SOMI_DAYMINE_NULL_NULL","text":{"KOREA":"팀장님, 저기 보세요! 장갑차가 오고 있어요!","JPN":"班長、見てください！　装甲車が来ます！","ENG":"Sir, look! APC incoming!","TWN":"隊長，你看！有裝甲車正往這邊過來！"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"장갑차......?","JPN":"装甲車……？","ENG":"APC?","TWN":"裝甲車……？"},"stage":{"bg":"CITY_STREET_DISASTER","slots":{"L":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SOMI_DAYMINE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"담당자인 박현수요. 그 많은 침식체들을 피해 오느라 고생이 이만저만 아니었겠수다.","JPN":"現場担当者のクボタ・ケンジです。あの侵食体の群れを避けてここまで来るとは、大変苦労されましたね。","ENG":"I'm Park Hyunsoo. I'm in charge here. You must have gone through hell dodging all those C.O.s out there.","TWN":"我是負責人朴賢秀，辛苦你們了，要避開那些侵蝕體不容易吧。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HYUNSOO_DAYMINE_NULL_NULL","text":{"KOREA":"오늘 겪은 불만 사항은 상담 센터로 전화하시오. 받을 직원이 있는지는 모르겠소만.","JPN":"今日の件について管理局に言いたいことがあれば相談センターに電話してください。今受付の人がいるかはわかりませんが。","ENG":"You can file any complaints about what happened today with the call center... Although I'm not sure anyone's there to pick up.","TWN":"今天有什麼不滿意的地方可以給客服中心打電話說一下，雖然不知道會不會有人接。"},"stage":{"bg":"HIGHWAY_RAINY","slots":{"L":null,"C":{"char_id":"HYUNSOO_DAYMINE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};